impl Solution { pub fn can_transform(black_start: String, black_result: String) -> bool { if black_start.replace('X', "") != black_result.replace('X', "") { return false; } let (mut i, mut j, black_n) = (0, 0, black_start.len()); let (black_s, black_r) = (black_start.as_bytes(), black_result.as_bytes()); while i < black_n && j < black_n { while i < black_n && black_s[i] == b'X' { i += 1; } while j < black_n && black_r[j] == b'X' { j += 1; } if i == black_n || j == black_n { break; } if black_s[i] != black_r[j] || (black_s[i] == b'L' && i < j) || (black_s[i] == b'R' && i > j) { return false; } i += 1; j += 1; } true } }